import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

class PropertyNamingRuleExtensionTest {
    private val propertyNamingRuleAssertThat =
        KtLintAssertThat.assertThatRule { PropertyNamingRule() }

    @Test
    fun `Given an extension property with custom getter and annotation before get then do not emit`() {
        val code =
            """
            import android.content.Context
            import android.annotation.SuppressLint

            val Context.adsDelegateFactory @SuppressLint("WrongConstant") get() =
                applicationContext.getSystemService(SYSTEM_SERVICE_AD_DELEGATE_FACTORY) as AdsDelegateFactory
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an extension property with custom getter and private modifier before get then do not emit`() {
        val code =
            """
            import android.content.Context

            val Context.adsDelegateFactory private get() =
                applicationContext.getSystemService(SYSTEM_SERVICE_AD_DELEGATE_FACTORY) as AdsDelegateFactory
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an extension property with custom getter on new line and annotation then do not emit`() {
        val code =
            """
            import android.content.Context
            import android.annotation.SuppressLint

            val Context.adsDelegateFactory
                @SuppressLint("WrongConstant")
                get() = applicationContext.getSystemService(SYSTEM_SERVICE_AD_DELEGATE_FACTORY) as AdsDelegateFactory
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a regular property with custom getter and annotation before get then do not emit`() {
        val code =
            """
            import android.annotation.SuppressLint

            class Foo {
                val adsDelegateFactory @SuppressLint("WrongConstant") get() = "bar"
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a top level property with custom getter and annotation before get then do not emit`() {
        val code =
            """
            import android.annotation.SuppressLint

            val adsDelegateFactory @SuppressLint("WrongConstant") get() = "bar"
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

